import React, { useState, useEffect } from "react";
import api from "../../api/axios";
import { Calendar, Clock, Video, MapPin, CalendarCheck, CheckCircle2, XCircle, ExternalLink, CalendarDays } from "lucide-react";

const MyMeetingsPage = () => {
    const [meetings, setMeetings] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchMyMeetings();
    }, []);

    const fetchMyMeetings = async () => {
        try {
            const res = await api.get("/meetings");
            setMeetings(res.data);
        } catch (err) {
            console.error("Failed to fetch meetings", err);
        } finally {
            setLoading(false);
        }
    };

    const handleResponse = async (id, status) => {
        try {
            await api.post(`/meetings/${id}/respond`, { status });
            alert(`Response recorded: ${status}`);
            fetchMyMeetings();
        } catch (err) {
            console.error("Failed to respond to meeting", err);
        }
    };

    // Google Calendar Link Generator (1 hour duration)
    const generateGCalLink = (meeting) => {
        const startDate = new Date(meeting.start_time);
        const endDate = new Date(startDate.getTime() + 60 * 60 * 1000); // +1 hour
        const start = startDate.toISOString().replace(/-|:|\.\d\d\d/g, "");
        const end = endDate.toISOString().replace(/-|:|\.\d\d\d/g, "");
        const details = encodeURIComponent(meeting.description || "");
        const location = encodeURIComponent(meeting.location || meeting.meeting_link || "");
        return `https://www.google.com/calendar/render?action=TEMPLATE&text=${encodeURIComponent(meeting.title)}&dates=${start}/${end}&details=${details}&location=${location}`;
    };

    const getStatusStyles = (status) => {
        switch (status) {
            case 'accepted': return 'bg-green-50 text-green-700 border-green-200 dark:bg-green-900/20 dark:text-green-300 dark:border-green-800';
            case 'declined': return 'bg-red-50 text-red-700 border-red-200 dark:bg-red-900/20 dark:text-red-300 dark:border-red-800';
            default: return 'bg-orange-50 text-orange-700 border-orange-200 dark:bg-orange-900/20 dark:text-orange-300 dark:border-orange-800';
        }
    };

    return (
        <div className="p-6 bg-gray-50 dark:bg-gray-900 min-h-full">
            <div className="mb-8">
                <h1 className="text-2xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
                    <CalendarCheck className="w-7 h-7 text-blue-600" /> My Meetings
                </h1>
                <p className="text-sm text-gray-500">Your upcoming sessions and syncs.</p>
            </div>

            {loading ? (
                <div className="flex justify-center p-12 text-gray-400 font-medium italic animate-pulse">Retrieving your schedule...</div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {meetings.map((meeting) => {
                        const myStatus = meeting.participants?.find(p => p.pivot)?.pivot?.attendance_status || 'pending';

                        return (
                            <div key={meeting.id} className="bg-white dark:bg-gray-800 rounded-2xl border border-gray-200 dark:border-gray-700 p-6 shadow-sm hover:shadow-lg transition-all flex flex-col group overflow-hidden relative">
                                <div className={`absolute top-0 right-0 px-3 py-1 text-[10px] font-bold uppercase tracking-widest rounded-bl-xl border-l border-b transition-colors ${getStatusStyles(myStatus)}`}>
                                    {myStatus}
                                </div>

                                <div className="mb-4 pr-16">
                                    <h3 className="text-lg font-bold text-gray-900 dark:text-white group-hover:text-blue-600 transition-colors leading-tight">{meeting.title}</h3>
                                    <p className="text-xs text-gray-500 mt-1 line-clamp-2">{meeting.description || 'No agenda provided.'}</p>
                                </div>

                                <div className="space-y-3 flex-1">
                                    <div className="bg-gray-50 dark:bg-gray-900/50 p-3 rounded-xl space-y-2 border border-gray-100 dark:border-gray-700/50">
                                        <div className="flex items-center gap-2 text-xs font-medium text-gray-600 dark:text-gray-400">
                                            <Clock className="w-3.5 h-3.5 text-blue-500" />
                                            <span>{new Date(meeting.start_time).toLocaleString('default', { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}</span>
                                        </div>
                                        {meeting.meeting_link && (
                                            <div className="flex items-center gap-2 text-xs font-bold text-blue-600">
                                                <Video className="w-3.5 h-3.5" />
                                                <a href={meeting.meeting_link} target="_blank" rel="noreferrer" className="hover:underline flex items-center gap-1">
                                                    Video Link <ExternalLink className="w-2.5 h-2.5" />
                                                </a>
                                            </div>
                                        )}
                                        {meeting.location && (
                                            <div className="flex items-center gap-2 text-xs font-medium text-gray-600 dark:text-gray-400">
                                                <MapPin className="w-3.5 h-3.5 text-red-500" />
                                                <span className="truncate">{meeting.location}</span>
                                            </div>
                                        )}
                                    </div>
                                </div>

                                <div className="mt-6 pt-6 border-t dark:border-gray-700">
                                    <div className="flex gap-2">
                                        {myStatus === 'pending' ? (
                                            <>
                                                <button
                                                    onClick={() => handleResponse(meeting.id, 'accepted')}
                                                    className="flex-1 bg-blue-600 hover:bg-blue-700 text-white py-2 px-3 rounded-xl text-xs font-bold transition-all shadow-md shadow-blue-200 dark:shadow-none flex items-center justify-center gap-2"
                                                >
                                                    <CheckCircle2 className="w-3.5 h-3.5" /> Accept
                                                </button>
                                                <button
                                                    onClick={() => handleResponse(meeting.id, 'declined')}
                                                    className="flex-1 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-400 py-2 px-3 rounded-xl text-xs font-bold hover:bg-red-50 hover:text-red-600 dark:hover:bg-red-900/10 transition-all flex items-center justify-center gap-2"
                                                >
                                                    <XCircle className="w-3.5 h-3.5" /> Decline
                                                </button>
                                            </>
                                        ) : (
                                            <a
                                                href={generateGCalLink(meeting)}
                                                target="_blank"
                                                rel="noreferrer"
                                                className="w-full bg-white dark:bg-gray-800 border-2 border-dashed border-gray-200 dark:border-gray-700 text-gray-500 py-2.5 rounded-xl text-xs font-bold hover:border-blue-400 hover:text-blue-500 transition-all flex items-center justify-center gap-2"
                                            >
                                                <CalendarDays className="w-4 h-4" /> Add to Google Calendar
                                            </a>
                                        )}
                                    </div>
                                    <div className="text-[9px] text-gray-400 mt-3 text-center uppercase tracking-tight font-medium italic">
                                        Organizer: {meeting.creator?.name}
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                    {meetings.length === 0 && (
                        <div className="col-span-full p-16 text-center bg-white dark:bg-gray-800 rounded-3xl border-2 border-dashed border-gray-100 dark:border-gray-700 shadow-inner">
                            <div className="bg-blue-50 dark:bg-blue-900/20 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                                <CalendarDays className="w-8 h-8 text-blue-400" />
                            </div>
                            <h3 className="text-lg font-bold text-gray-800 dark:text-white">Clear Schedule!</h3>
                            <p className="text-gray-500 text-sm">You don't have any meetings scheduled at the moment.</p>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

export default MyMeetingsPage;
